uint32_t wmma64_ab_lane(uint32_t row_or_col, uint32_t k) {
  return row_or_col + 16u * ((k >> 2) & 1u);
}

uint32_t wmma64_ab_index(uint32_t k) {
  const uint32_t reg =
      ((k >> 1) & 1u) + 2u * ((k >> 3) & 1u) + 4u * ((k >> 4) & 1u) + 8u * ((k >> 5) & 1u);
  return 2u * reg + (k & 1u);
}

void write_packed_byte(amdgpu::ComputeUnitCore &cu, uint32_t reg, uint32_t lane, uint32_t byte,
                       uint8_t value) {
  const uint32_t shift = 8u * byte;
  const uint32_t old = cu.read_vgpr(reg, lane);
  cu.write_vgpr(reg, lane, (old & ~(0xFFu << shift)) | (static_cast<uint32_t>(value) << shift));
}

void write_packed_half(amdgpu::ComputeUnitCore &cu, uint32_t reg, uint32_t lane, uint32_t half,
                       uint16_t value) {
  const uint32_t shift = 16u * half;
  const uint32_t old = cu.read_vgpr(reg, lane);
  cu.write_vgpr(reg, lane, (old & ~(0xFFFFu << shift)) | (static_cast<uint32_t>(value) << shift));
}

void fill_vgprs(amdgpu::ComputeUnitCore &cu, uint32_t base, uint32_t regs, uint32_t lanes,
                uint32_t value) {
  for (uint32_t reg = 0; reg < regs; ++reg)
    for (uint32_t lane = 0; lane < lanes; ++lane)
      cu.write_vgpr(base + reg, lane, value);
}

void write_wmma_f8_input(amdgpu::ComputeUnitCore &cu, uint32_t base, amdgpu::InputLoc loc,
                         uint8_t value) {
  ASSERT_EQ(loc.data_bits, 8u);
  ASSERT_LT(loc.bit_offset, 32u);
  write_packed_byte(cu, base + loc.vgpr_offset, loc.lane, loc.sub_element, value);
}

struct ForceScalarGuard {
  explicit ForceScalarGuard(bool force_scalar) : old_force_scalar(util::force_scalar()) {
    util::set_force_scalar_for_testing(force_scalar);
  }
  ~ForceScalarGuard() { util::set_force_scalar_for_testing(old_force_scalar); }

  bool old_force_scalar;
};

float wmma_test_a(uint32_t row, uint32_t k) {
  return static_cast<float>(static_cast<int>((row + k) % 5u) - 2);
}

float wmma_test_b(uint32_t k, uint32_t col) {
  return static_cast<float>(static_cast<int>((col + 3u * k) % 5u) - 2);
}

float wmma_test_c(uint32_t row, uint32_t col) {
  return static_cast<float>(static_cast<int>((2u * row + col) % 7u) - 3);
}

TEST(Gfx1250WmmaTest, F8SpecK128UsesPairAwareInputLocators) {
  if constexpr (!util::has_stdx_simd) {
    GTEST_SKIP() << "<experimental/simd> unavailable";
  } else if (util::native<float>::size() != 16) {
    GTEST_SKIP() << "specialized f8 WMMA SIMD fast path requires 16-wide native<float>";
  }

  ForceScalarGuard force_simd(false);
  amdgpu::GpuMemory gpu_mem("gfx1250_wmma_f8_spec_k128_locator_mem");
  amdgpu::L2Cache l2("gfx1250_wmma_f8_spec_k128_locator_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_EQ(wf->wf_size(), 32u);
  wf->set_exec((1ULL << wf->wf_size()) - 1ULL);

  const uint32_t vb = wf->vgpr_alloc().base;
  const uint32_t a_base = vb + 10;
  const uint32_t b_base = vb + 30;
  const uint32_t c_base = vb + 50;
  const uint32_t d_base = vb + 70;
  constexpr uint32_t kProbeRow = 3;
  constexpr uint32_t kProbeCol = 5;
  constexpr uint32_t kProbeK = 4;

  auto clear_wmma_state = [&] {
    fill_vgprs(*cu, a_base, 16, wf->wf_size(), 0);
    fill_vgprs(*cu, b_base, 16, wf->wf_size(), 0);
    fill_vgprs(*cu, c_base, 8, wf->wf_size(), 0);
    fill_vgprs(*cu, d_base, 8, wf->wf_size(), 0xDEADBEEFu);
  };

  clear_wmma_state();
  write_wmma_f8_input(*cu, a_base, amdgpu::wmma_a_input_loc(16, 128, kProbeRow, kProbeK, 8, 8),
                      util::f32_to_fp8_e4m3_rne(1.0f));
  write_wmma_f8_input(*cu, b_base, amdgpu::wmma_b_input_loc(16, 128, kProbeCol, kProbeK, 8, 8),
                      util::f32_to_bf8_e5m2_rne(1.0f));

  amdgpu::exec_wmma_f32_f8_spec<16, 16, 128, true, false>(*cu, d_base, a_base, b_base, c_base,
                                                          amdgpu::ACC_FROM_VGPR);

  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t col = 0; col < 16; ++col) {
      const auto out = amdgpu::wmma_output_loc_32(16, 16, row, col);
      const float expected = (row == kProbeRow && col == kProbeCol) ? 1.0f : 0.0f;
      EXPECT_EQ(cu->read_vgpr(d_base + out.reg, out.lane), std::bit_cast<uint32_t>(expected))
          << "f32 row=" << row << " col=" << col;
    }
  }

  clear_wmma_state();
  write_wmma_f8_input(*cu, a_base, amdgpu::wmma_a_input_loc(16, 128, kProbeRow, kProbeK, 8, 8),
                      util::f32_to_bf8_e5m2_rne(1.0f));
  write_wmma_f8_input(*cu, b_base, amdgpu::wmma_b_input_loc(16, 128, kProbeCol, kProbeK, 8, 8),
                      util::f32_to_fp8_e4m3_rne(1.0f));

  amdgpu::exec_wmma_f16_f8_spec<16, 16, 128, false, true>(*cu, d_base, a_base, b_base, c_base,
                                                          amdgpu::ACC_FROM_VGPR);

  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t col = 0; col < 16; ++col) {
      const auto out = amdgpu::wmma_output_loc_16(16, 16, row, col);
      const uint32_t raw = cu->read_vgpr(d_base + out.reg, out.lane);
      const auto actual = static_cast<uint16_t>((raw >> (16u * out.sub_element)) & 0xFFFFu);
      const uint16_t expected =
          (row == kProbeRow && col == kProbeCol) ? util::f32_to_f16(1.0f) : 0u;
      EXPECT_EQ(actual, expected) << "f16 row=" << row << " col=" << col;
    }
  }

  cu->reset_all_wf();
}

TEST(Gfx1250WmmaTest, F16Fp8K64MatchesReferenceLayout) {
  amdgpu::GpuMemory gpu_mem("gfx1250_wmma_f16_fp8_k64_mem");
  amdgpu::L2Cache l2("gfx1250_wmma_f16_fp8_k64_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_EQ(wf->wf_size(), 32u);
  wf->set_exec((1ULL << wf->wf_size()) - 1ULL);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_GFX1250);
  ASSERT_NE(decoder, nullptr);

  const uint32_t vb = wf->vgpr_alloc().base;
  const uint32_t a_base = vb + 10;
  const uint32_t b_base = vb + 20;
  const uint32_t c_base = vb + 30;
  const uint32_t d_base = vb + 40;

  for (uint32_t reg = 0; reg < 8; ++reg) {
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
      cu->write_vgpr(a_base + reg, lane, 0);
      cu->write_vgpr(b_base + reg, lane, 0);
    }
  }
  for (uint32_t reg = 0; reg < 4; ++reg) {
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
      cu->write_vgpr(c_base + reg, lane, 0);
      cu->write_vgpr(d_base + reg, lane, 0xDEADBEEFu);
    }
  }

  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t k = 0; k < 64; ++k) {
      const uint32_t idx = wmma64_ab_index(k);
      write_packed_byte(*cu, a_base + idx / 4u, wmma64_ab_lane(row, k), idx % 4u,
                        util::f32_to_fp8_e4m3_rne(wmma_test_a(row, k)));
    }
  }
  for (uint32_t k = 0; k < 64; ++k) {
    for (uint32_t col = 0; col < 16; ++col) {
      const uint32_t idx = wmma64_ab_index(k);
      write_packed_byte(*cu, b_base + idx / 4u, wmma64_ab_lane(col, k), idx % 4u,
                        util::f32_to_fp8_e4m3_rne(wmma_test_b(k, col)));
    }
  }
  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t col = 0; col < 16; ++col) {
      const auto out = amdgpu::wmma_output_loc_16(16, 16, row, col);
      write_packed_half(*cu, c_base + out.reg, out.lane, out.sub_element,
                        util::f32_to_f16(wmma_test_c(row, col)));
    }
  }

  amdgpu::exec_wmma_f16(*cu, 16, 16, 64, 8, d_base, a_base, b_base, c_base, amdgpu::extract_fp8,
                        amdgpu::extract_fp8, amdgpu::ACC_FROM_VGPR);

  auto expect_reference = [&] {
    for (uint32_t row = 0; row < 16; ++row) {
      for (uint32_t col = 0; col < 16; ++col) {
        float ref = wmma_test_c(row, col);
        for (uint32_t k = 0; k < 64; ++k)
          ref += wmma_test_a(row, k) * wmma_test_b(k, col);
        const auto out = amdgpu::wmma_output_loc_16(16, 16, row, col);
        const uint32_t raw = cu->read_vgpr(d_base + out.reg, out.lane);
        const auto actual = static_cast<uint16_t>((raw >> (16u * out.sub_element)) & 0xFFFFu);
        EXPECT_EQ(actual, util::f32_to_f16(ref)) << "row=" << row << " col=" << col;
      }
    }
  };
  expect_reference();

  for (uint32_t reg = 0; reg < 4; ++reg)
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane)
      cu->write_vgpr(d_base + reg, lane, 0xDEADBEEFu);

  const uint32_t wmma_words[] = {
      0xCC6E0000U | 40u,
      (256u + 10u) | ((256u + 20u) << 9u) | ((256u + 30u) << 18u),
  };
  std::unique_ptr<Instruction> inst(decoder->decode(wmma_words));
  ASSERT_NE(inst, nullptr);
  ASSERT_EQ(std::string_view(inst->mnemonic()), "v_wmma_f16_16x16x64_fp8_fp8");
  cu->execute_instruction(inst.get(), *wf);
  expect_reference();

  cu->reset_all_wf();
}

TEST(Gfx1250WmmaTest, CModifierAppliesAbsBeforeNegate) {
  EXPECT_EQ(amdgpu::wmma_c_modifier(0u, 0u), 0u);
  EXPECT_EQ(amdgpu::wmma_c_modifier(1u << 2u, 0u), 1u);
  EXPECT_EQ(amdgpu::wmma_c_modifier(0u, 1u << 2u), 2u);
  EXPECT_EQ(amdgpu::wmma_c_modifier(1u << 2u, 1u << 2u), 3u);

  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 0u), -3.0f);
  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 1u), 3.0f);
  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 2u), 3.0f);
  EXPECT_EQ(amdgpu::apply_wmma_c_modifier(-3.0f, 3u), -3.0f);
}

TEST(Gfx1250WmmaTest, E8M0ScaleZeroMatchesUtilContract) {
  EXPECT_EQ(std::bit_cast<uint32_t>(amdgpu::decode_wmma_scale_byte(0x00, 0)),
            std::bit_cast<uint32_t>(util::e8m0_to_f32(0x00)));
  EXPECT_TRUE(std::isnan(amdgpu::decode_wmma_scale_byte(0xff, 0)));
}

TEST(Gfx1250WmmaTest, Bf16F32K32Bf16PreservesAccumulatorLayout) {
  amdgpu::GpuMemory gpu_mem("gfx1250_wmma_bf16f32_k32_bf16_mem");
  amdgpu::L2Cache l2("gfx1250_wmma_bf16f32_k32_bf16_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_EQ(wf->wf_size(), 32u);
  wf->set_exec((1ULL << wf->wf_size()) - 1ULL);

  const uint32_t vb = wf->vgpr_alloc().base;
  const uint32_t a_base = vb + 10;
  const uint32_t b_base = vb + 20;
  const uint32_t c_base = vb + 30;
  const uint32_t d_base = vb + 40;

  for (uint32_t reg = 0; reg < 8; ++reg) {
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
      cu->write_vgpr(a_base + reg, lane, 0);
      cu->write_vgpr(b_base + reg, lane, 0);
      cu->write_vgpr(c_base + reg, lane, 0);
    }
  }
  for (uint32_t reg = 0; reg < 4; ++reg)
    for (uint32_t lane = 0; lane < wf->wf_size(); ++lane)
      cu->write_vgpr(d_base + reg, lane, 0xDEADBEEFu);

  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t k = 0; k < 32; ++k) {
      const auto in = amdgpu::wmma_input_loc(16, 32, row, k, 16);
      write_packed_half(*cu, a_base + in.vgpr_offset, in.lane, in.sub_element,
                        util::f32_to_bf16(wmma_test_a(row, k)));
    }
  }
  for (uint32_t k = 0; k < 32; ++k) {
    for (uint32_t col = 0; col < 16; ++col) {
      const auto in = amdgpu::wmma_input_loc(16, 32, col, k, 16);
      write_packed_half(*cu, b_base + in.vgpr_offset, in.lane, in.sub_element,
                        util::f32_to_bf16(wmma_test_b(k, col)));
    }
  }
  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t col = 0; col < 16; ++col) {
      const auto out = amdgpu::wmma_output_loc_32(16, 16, row, col);
      cu->write_vgpr(c_base + out.reg, out.lane, std::bit_cast<uint32_t>(wmma_test_c(row, col)));
    }
  }

  amdgpu::exec_wmma_bf16f32_16x16x32_bf16(*cu, d_base, a_base, b_base, c_base);

  for (uint32_t row = 0; row < 16; ++row) {
    for (uint32_t col = 0; col < 16; ++col) {
      float ref = wmma_test_c(row, col);
      for (uint32_t k = 0; k < 32; ++k)
        ref += wmma_test_a(row, k) * wmma_test_b(k, col);
      const auto out = amdgpu::wmma_output_loc_16(16, 16, row, col);
      const uint32_t raw = cu->read_vgpr(d_base + out.reg, out.lane);
      const auto actual = static_cast<uint16_t>((raw >> (16u * out.sub_element)) & 0xFFFFu);
      EXPECT_EQ(actual, util::f32_to_bf16(ref)) << "row=" << row << " col=" << col;
    }
  }

  cu->reset_all_wf();
}

TEST(Gfx1250Dpp8Test, Vop2AddF16UsesPermutedSourceLanes) {
  amdgpu::GpuMemory gpu_mem("gfx1250_dpp8_add_f16_mem");
  amdgpu::L2Cache l2("gfx1250_dpp8_add_f16_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_GFX1250);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_EQ(wf->wf_size(), 32u);
  wf->set_exec((1ULL << wf->wf_size()) - 1ULL);

  const uint32_t vb = wf->vgpr_alloc().base;
  constexpr uint32_t kSrc0 = 2;
  constexpr uint32_t kSrc1 = 3;
  constexpr uint32_t kDst = 4;
  const uint32_t lane_sel = (7u << 0u) | (0u << 3u) | (3u << 6u) | (2u << 9u) | (5u << 12u) |
                            (4u << 15u) | (1u << 18u) | (6u << 21u);

  for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
    cu->write_vgpr(vb + kSrc0, lane, util::f32_to_f16(static_cast<float>(lane + 1)));
    cu->write_vgpr(vb + kSrc1, lane, util::f32_to_f16(0.0f));
    cu->write_vgpr(vb + kDst, lane, 0xDEAD0000u);
  }

  const uint32_t add_f16_dpp8_words[] = {
      0x64000000u | amdgpu::SRC_DPP8_LO | (kSrc1 << 9u) | (kDst << 17u),
      kSrc0 | (lane_sel << 8u),
  };
  std::unique_ptr<Instruction> inst(decoder->decode(add_f16_dpp8_words));
  ASSERT_NE(inst, nullptr);
  ASSERT_EQ(std::string_view(inst->mnemonic()), "v_add_f16_e32");
  cu->execute_instruction(inst.get(), *wf);

  for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
    const uint32_t src_lane = amdgpu::dpp::dpp8_src_lane(lane, lane_sel);
    const uint32_t raw = cu->read_vgpr(vb + kDst, lane);
    EXPECT_EQ(raw >> 16, 0xDEADu) << "lane=" << lane;
    EXPECT_EQ(raw & 0xFFFFu, util::f32_to_f16(static_cast<float>(src_lane + 1))) << "lane=" << lane;
  }

  cu->reset_all_wf();
}

TEST(Gfx1250ExecMaskTest, CmpxNeqAndScalarOrRestoreExec) {
  amdgpu::GpuMemory gpu_mem("gfx1250_exec_mask_mem");
  amdgpu::L2Cache l2("gfx1250_exec_mask_l2");

  amdgpu::ComputeUnitCore::Config cfg{};
  cfg.arch = ROCJITSU_CODE_ARCH_GFX1250;
  cfg.num_wf_slots = 1;
  cfg.sgprs_per_wf = 106;
  cfg.vgprs_per_wf = 256;
  cfg.lds_size_kb = 64;

  auto cu = amdgpu::ComputeUnitCore::create("gfx1250", cfg, &gpu_mem, &l2);
  ASSERT_NE(cu, nullptr);

  auto decoder = Decoder::create(ROCJITSU_CODE_ARCH_GFX1250);
  ASSERT_NE(decoder, nullptr);

  auto *wf = cu->dispatch_wf(0, 0, cfg.sgprs_per_wf, cfg.vgprs_per_wf);
  ASSERT_NE(wf, nullptr);
  ASSERT_LE(wf->wf_size(), 64u);
  const uint64_t all_lanes = wf->wf_size() == 64 ? ~0ULL : ((1ULL << wf->wf_size()) - 1ULL);
  wf->set_exec(all_lanes);

  // s_mov_b32 s1, exec_lo
  const uint32_t save_exec_words[] = {0xBE81007EU, 0};
  std::unique_ptr<Instruction> save_exec(decoder->decode(save_exec_words));
  ASSERT_NE(save_exec, nullptr);
  ASSERT_EQ(std::string_view(save_exec->mnemonic()), "s_mov_b32");
  cu->execute_instruction(save_exec.get(), *wf);
  EXPECT_EQ(cu->read_sgpr(wf->sgpr_alloc().base + 1), static_cast<uint32_t>(all_lanes));

  const uint32_t v4 = wf->vgpr_alloc().base + 4;
  for (uint32_t lane = 0; lane < wf->wf_size(); ++lane) {
    const float value = lane == 4 ? 0.0f : 1.0f;
    cu->write_vgpr(v4, lane, std::bit_cast<uint32_t>(value));
  }

  // v_cmpx_neq_f32_e32 0, v4
  const uint32_t mask_zero_lane_words[] = {0x7D3A0880U, 0};
  std::unique_ptr<Instruction> mask_zero_lane(decoder->decode(mask_zero_lane_words));
  ASSERT_NE(mask_zero_lane, nullptr);
  ASSERT_EQ(std::string_view(mask_zero_lane->mnemonic()), "v_cmpx_neq_f32_e32");
  cu->execute_instruction(mask_zero_lane.get(), *wf);
  EXPECT_EQ(wf->exec(), all_lanes & ~(1ULL << 4));

  // s_or_b32 exec_lo, exec_lo, s1
  const uint32_t restore_exec_words[] = {0x8C7E017EU, 0};
  std::unique_ptr<Instruction> restore_exec(decoder->decode(restore_exec_words));
  ASSERT_NE(restore_exec, nullptr);
  ASSERT_EQ(std::string_view(restore_exec->mnemonic()), "s_or_b32");
  cu->execute_instruction(restore_exec.get(), *wf);
  EXPECT_EQ(wf->exec(), all_lanes);

  cu->reset_all_wf();
}

